import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-lg text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-indigo-500 focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-indigo-500 text-white hover:bg-indigo-600 shadow-sm",
        destructive: "bg-rose-500 text-white hover:bg-rose-600 shadow-sm",
        outline: "border border-stone-200 bg-white hover:bg-stone-50 text-stone-700 dark:border-[var(--dark-border)] dark:bg-[var(--dark-card)] dark:text-stone-300 dark:hover:bg-[var(--dark-hover)]",
        secondary: "bg-stone-100 text-stone-900 hover:bg-stone-200 dark:bg-[var(--dark-elevated)] dark:text-stone-100 dark:hover:bg-[var(--dark-hover)]",
        ghost: "hover:bg-stone-100 text-stone-700 dark:text-stone-300 dark:hover:bg-[var(--dark-hover)]",
        link: "text-indigo-500 underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-xl px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button"
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    )
  }
)
Button.displayName = "Button"

// eslint-disable-next-line react-refresh/only-export-components
export { Button, buttonVariants }
